const DatePicker={currentDate:null,selectedDate:null,onSelect:null,init(){this.currentDate=new Date,this.selectedDate=new Date,this.createPicker()},createPicker(){document.getElementById("datePickerModal")||(document.body.insertAdjacentHTML("beforeend",'\n            <div class="date-picker-modal" id="datePickerModal">\n                <div class="date-picker-content">\n                    <div class="date-picker-header">\n                        <button class="date-picker-cancel" id="datePickerCancel">取消</button>\n                        <h3>选择日期</h3>\n                        <button class="date-picker-confirm" id="datePickerConfirm">确定</button>\n                    </div>\n                    <div class="date-picker-quick">\n                        <button class="quick-btn" data-offset="0">今天</button>\n                        <button class="quick-btn" data-offset="1">明天</button>\n                        <button class="quick-btn" data-offset="2">后天</button>\n                        <button class="quick-btn custom" id="customDateBtn">自定义</button>\n                    </div>\n                    <div class="date-picker-calendar" id="datePickerCalendar">\n                        <div class="date-picker-month">\n                            <button class="month-nav" id="prevMonth">‹</button>\n                            <span id="currentMonthLabel"></span>\n                            <button class="month-nav" id="nextMonth">›</button>\n                        </div>\n                        <div class="date-picker-weekdays">\n                            <div>日</div>\n                            <div>一</div>\n                            <div>二</div>\n                            <div>三</div>\n                            <div>四</div>\n                            <div>五</div>\n                            <div>六</div>\n                        </div>\n                        <div class="date-picker-days" id="datePickerDays"></div>\n                    </div>\n                </div>\n            </div>\n        '),this.bindEvents())},bindEvents(){document.getElementById("datePickerCancel").addEventListener("click",(()=>this.hide())),document.getElementById("datePickerConfirm").addEventListener("click",(()=>this.confirm())),document.querySelectorAll(".quick-btn:not(.custom)").forEach((e=>{e.addEventListener("click",(()=>{const t=parseInt(e.dataset.offset),n=new Date;n.setDate(n.getDate()+t),this.selectedDate=n,this.highlightSelectedDate(),document.querySelectorAll(".quick-btn").forEach((e=>e.classList.remove("active"))),e.classList.add("active")}))})),document.getElementById("customDateBtn").addEventListener("click",(()=>{document.getElementById("datePickerCalendar").classList.toggle("show")})),document.getElementById("prevMonth").addEventListener("click",(()=>this.navigateMonth(-1))),document.getElementById("nextMonth").addEventListener("click",(()=>this.navigateMonth(1)))},show(e,t){this.selectedDate=e?new Date(e+"T00:00:00"):new Date,this.currentDate=new Date(this.selectedDate),this.onSelect=t,this.renderCalendar(),document.getElementById("datePickerModal").classList.add("show")},hide(){document.getElementById("datePickerModal").classList.remove("show"),document.getElementById("datePickerCalendar").classList.remove("show")},confirm(){if(this.onSelect){const e=this.selectedDate.getFullYear(),t=String(this.selectedDate.getMonth()+1).padStart(2,"0"),n=String(this.selectedDate.getDate()).padStart(2,"0");this.onSelect(`${e}-${t}-${n}`)}this.hide()},renderCalendar(){const e=this.currentDate.getFullYear(),t=this.currentDate.getMonth();document.getElementById("currentMonthLabel").textContent=`${e}年${t+1}月`;const n=new Date(e,t,1),a=new Date(e,t+1,0),d=n.getDay(),i=a.getDate(),c=new Date(e,t,0).getDate(),s=new Date,r=this.formatDate(s),o=this.formatDate(this.selectedDate);let l="";for(let e=d-1;e>=0;e--){l+=`<div class="picker-day other-month">${c-e}</div>`}for(let n=1;n<=i;n++){const a=new Date(e,t,n),d=this.formatDate(a);let i="picker-day";d===r&&(i+=" today"),d===o&&(i+=" selected"),l+=`<div class="${i}" data-date="${d}">${n}</div>`}const h=(7-(d+i)%7)%7;for(let e=1;e<=h;e++)l+=`<div class="picker-day other-month">${e}</div>`;document.getElementById("datePickerDays").innerHTML=l,document.querySelectorAll(".picker-day:not(.other-month)").forEach((e=>{e.addEventListener("click",(()=>{this.selectedDate=new Date(e.dataset.date+"T00:00:00"),this.highlightSelectedDate(),document.querySelectorAll(".quick-btn").forEach((e=>e.classList.remove("active")))}))}))},navigateMonth(e){this.currentDate.setMonth(this.currentDate.getMonth()+e),this.renderCalendar()},highlightSelectedDate(){document.querySelectorAll(".picker-day").forEach((e=>{e.classList.remove("selected"),e.dataset.date===this.formatDate(this.selectedDate)&&e.classList.add("selected")}))},formatDate:e=>`${e.getFullYear()}-${String(e.getMonth()+1).padStart(2,"0")}-${String(e.getDate()).padStart(2,"0")}`};